#include<bits/stdc++.h>
using namespace std;
int n,k,q,d[200010],x[200010],fa1[200010],d1[200010],dis1[200010],lg[200010],y[200010],dis[200010],fa[200010][21];
bool vis[200010],flag[200010];
vector<int> mp[200010],mp1[200010];
void bfs()
{
    memset(vis,0,sizeof(vis));
    vis[n+1]=true;
    queue<int> q;
    q.push(n+1);
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        int f=fa1[t];
        for(int i:mp1[t])
        {
            if(i!=f&&!vis[i])
            {
                vis[i]=true;
                dis1[i]=dis1[t]+1;
                q.push(i);
            }
        }
    }
}
void dfs(int x,int f=0)
{
    fa[x][0]=f;
    d[x]=d[f]+1;
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        if(i!=f)
        {
            dis[i]=dis[x]+1;
            dfs(i,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
int main()
{
    scanf("%d%d%d",&n,&k,&q);
    for(int i=1;i<n;i++)
    {
        scanf("%d%d",&x[i],&y[i]);
    }
    for(int i=1;i<=n;i++)
    {
        lg[i]=__lg(i);
    }
    for(int i=1;i<=k;i++)
    {
        int x;
        scanf("%d",&x);
        flag[x]=true;
    }
    if(k==0)
    {
        for(int i=1;i<n;i++)
        {
            mp[x[i]].push_back(y[i]);
            mp[y[i]].push_back(x[i]);
        }
        dfs(1);
        while(q--)
        {
            int x,y;
            scanf("%d%d",&x,&y);
            int l=lca(x,y);
            printf("%d\n",dis[x]+dis[y]-dis[l]*2);
        }
        return 0;
    }
    for(int i=1;i<n;i++)
    {
        mp[x[i]].push_back(y[i]);
        mp[y[i]].push_back(x[i]);
        if(flag[x[i]]&&flag[y[i]])
        {
            continue;
        }
        if(!flag[x[i]]&&!flag[y[i]])
        {
            mp1[x[i]].push_back(y[i]);
            mp1[y[i]].push_back(x[i]);
            continue;
        }
        if(!flag[x[i]])
        {
            swap(x[i],y[i]);
        }
        mp1[n+1].push_back(y[i]);
        mp1[y[i]].push_back(n+1);
    }
    dfs(1);
    bfs();
    while(q--)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        if((flag[x]&&flag[y])||x==y)
        {
            printf("0\n");
            continue;
        }
        if(flag[x])
        {
            printf("%d\n",dis1[y]);
            continue;
        }
        if(flag[y])
        {
            printf("%d\n",dis1[x]);
            continue;
        }
        int l=lca(x,y);
        printf("%d\n",min(dis[x]+dis[y]-dis[l]*2,dis1[x]+dis1[y]));
    }
    return 0;
}
